  return (
    <div className="max-w-4xl mx-auto p-4 md:p-6 space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-800">Pending Approvals</h2>
        <div className="text-sm text-gray-500 font-medium bg-gray-100 px-3 py-1 rounded-full">
          {pendingEvents.length} Pending
        </div>
      </div>

      {pendingEvents.length === 0 ? (
        <div className="bg-white rounded-2xl p-12 text-center border border-dashed border-gray-300">
          <div className="mx-auto w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mb-4 text-gray-400">
            <Check size={32} />
          </div>
          <h3 className="text-lg font-medium text-gray-900">All caught up!</h3>
          <p className="text-gray-500 mt-1">There are no events waiting for approval.</p>
        </div>
      ) : (
        <div className="grid gap-4">
          {pendingEvents.map((event) => (
