                    <div key={event.id} className="bg-white rounded-xl p-5 border border-amber-200 shadow-sm relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-1 h-full bg-amber-400"></div>
                        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                            <div className="space-y-3 flex-1">
                                <div className="flex items-center gap-2 mb-1">
                                    <span className="text-xs font-bold text-amber-600 uppercase tracking-wide">Modified Event</span>
                                    <span className={`px-2 py-0.5 rounded-md text-[10px] font-semibold ${getRegionClasses(event.region)}`}>
                                        {event.region}
                                    </span>
                                </div>

                                <div>
                                    <h3 className="text-lg font-bold text-gray-900 leading-tight">{event.title}</h3>
                                    {event.description && (
                                        <p className="text-gray-600 text-sm mt-1 line-clamp-2">{event.description}</p>
                                    )}
                                </div>

                                <div className="flex flex-col gap-1.5 mt-1">
                                    <div className="flex items-center gap-2 text-sm text-gray-600">
                                        <CalendarIcon size={14} className="shrink-0 text-gray-400" />
                                        <div className="flex flex-wrap gap-2 items-center">
                                            <span className="whitespace-nowrap">
                                                {formatFriendlyDate(event.start)}
                                                {!event.isAllDay && <span className="ml-1.5 font-medium text-gray-900">{formatTime(event.start)}</span>}
                                            </span>
                                            <ArrowRight size={12} className="text-gray-400" />
                                            <span className="whitespace-nowrap">
                                                {formatFriendlyDate(event.end)}
