import React, { useEffect, useState } from 'react';
import { CalendarEvent } from '../types';
import { getPendingEvents, getRejectedEvents, getEditedEvents, updateEvent, approveEditedEvent, rejectEditedEvent } from '../lib/firebase';
import { Check, X, MapPin, Calendar as CalendarIcon, Loader2, ArrowRight, RotateCcw, AlertTriangle, FileText, Globe, Clock, ArrowRight as ArrowIcon } from 'lucide-react';
import { formatFriendlyDate, formatTime, getRegionClasses } from '../utils/dateUtils';

export const AdminDashboard: React.FC = () => {
  const [pendingEvents, setPendingEvents] = useState<CalendarEvent[]>([]);
  const [editedEvents, setEditedEvents] = useState<CalendarEvent[]>([]);
  const [rejectedEvents, setRejectedEvents] = useState<CalendarEvent[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribePending = getPendingEvents((events) => {
      setPendingEvents(events);
      setLoading(false);
    });

    const unsubscribeEdited = getEditedEvents((events) => {
      setEditedEvents(events);
    });

    const unsubscribeRejected = getRejectedEvents((events) => {
      setRejectedEvents(events);
    });

    return () => {
        unsubscribePending();
        unsubscribeEdited();
        unsubscribeRejected();
    };
  }, []);

  const handleStatusChange = async (event: CalendarEvent, newStatus: 'approved' | 'rejected' | 'pending') => {
    try {
      await updateEvent({ ...event, status: newStatus });
    } catch (e) {
      console.error("Failed to update status", e);
      alert("Failed to update status. Please try again.");
    }
  };

  const handleEditApproval = async (event: CalendarEvent, approved: boolean) => {
      try {
          if (approved) {
              await approveEditedEvent(event);
          } else {
              await rejectEditedEvent(event);
          }
      } catch (e) {
          console.error("Failed to process edit approval", e);
          alert("Failed to process action. Please try again.");
      }
  };

  // Helper to check for changes
  const hasChanges = (event: CalendarEvent) => {
      if (!event.originalData) return {};
      const orig = event.originalData;
      return {
          title: event.title !== orig.title,
          description: (event.description || '') !== (orig.description || ''),
          location: (event.location || '') !== (orig.location || ''),
          region: event.region !== orig.region,
          time: event.start !== orig.start || event.end !== orig.end || event.isAllDay !== orig.isAllDay,
          recurrence: (event.recurrence || 'none') !== (orig.recurrence || 'none')
      };
  };

  const renderTime = (e: CalendarEvent | undefined) => {
      if (!e) return null;
      return (
        <div className="flex flex-wrap gap-2 items-center">
            <span className="whitespace-nowrap">
                {formatFriendlyDate(e.start)}
                {!e.isAllDay && <span className="ml-1.5 font-medium">{formatTime(e.start)}</span>}
            </span>
            <ArrowRight size={12} className="text-gray-400" />
            <span className="whitespace-nowrap">
                {formatFriendlyDate(e.end)}
                {!e.isAllDay && <span className="ml-1.5 font-medium">{formatTime(e.end)}</span>}
            </span>
        </div>
      );
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full min-h-[400px]">
        <Loader2 className="animate-spin text-blue-600" size={32} />
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-6 space-y-12">

      {/* Edited Events Section */}
      {editedEvents.length > 0 && (
          <section className="space-y-6">
            <div className="flex items-center justify-between">
                <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
                    <span className="p-1 bg-amber-100 rounded-md text-amber-600"><AlertTriangle size={20} /></span>
                    Pending Edits
                </h2>
                <div className="text-sm text-amber-700 font-medium bg-amber-50 border border-amber-100 px-3 py-1 rounded-full">
                    {editedEvents.length} Edited
                </div>
            </div>

            <div className="grid gap-6">
                {editedEvents.map((event) => {
                    const changes = hasChanges(event);
                    const original = event.originalData;

                    return (
                        <div key={event.id} className="bg-white rounded-xl border border-amber-200 shadow-sm relative overflow-hidden">
                            <div className="absolute top-0 left-0 w-1.5 h-full bg-amber-400"></div>

                            <div className="p-5 flex flex-col gap-4">
                                {/* Header: Status and Region */}
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-2">
                                        <span className="text-xs font-bold text-amber-600 uppercase tracking-wide bg-amber-50 px-2 py-1 rounded">
                                            Edits for Review
                                        </span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        {changes.region ? (
                                            <div className="flex items-center gap-2 text-xs">
                                                <span className={`px-2 py-0.5 rounded-md font-semibold opacity-50 line-through ${original ? getRegionClasses(original.region) : ''}`}>
                                                    {original?.region}
                                                </span>
                                                <ArrowIcon size={12} className="text-gray-400" />
                                                <span className={`px-2 py-0.5 rounded-md font-semibold ring-2 ring-amber-400 ${getRegionClasses(event.region)}`}>
                                                    {event.region}
                                                </span>
                                            </div>
                                        ) : (
                                            <span className={`px-2 py-0.5 rounded-md text-xs font-semibold ${getRegionClasses(event.region)}`}>
                                                {event.region}
                                            </span>
                                        )}
                                    </div>
                                </div>

                                {/* Title Diff */}
                                <div>
                                    {changes.title ? (
                                        <div className="space-y-1">
                                            <div className="flex items-start gap-2">
                                                <h3 className="text-lg font-bold text-gray-900 leading-tight bg-green-50 px-1 rounded -ml-1 border border-green-100">
                                                    {event.title}
                                                </h3>
                                            </div>
                                            <p className="text-sm text-red-400 line-through flex items-center gap-1">
                                                <span className="text-xs font-medium uppercase no-underline text-red-300 mr-1">Was:</span>
                                                {original?.title}
                                            </p>
                                        </div>
                                    ) : (
                                        <h3 className="text-lg font-bold text-gray-900 leading-tight">{event.title}</h3>
                                    )}
                                </div>

                                <div className="space-y-3">
                                    {/* Description Diff */}
                                    <div className={`p-3 rounded-lg ${changes.description ? 'bg-amber-50/50 border border-amber-100' : 'bg-gray-50'}`}>
                                        <div className="flex items-center gap-2 mb-1.5">
                                            <FileText size={14} className="text-gray-400" />
                                            <span className="text-xs font-semibold text-gray-500 uppercase">Description</span>
                                            {changes.description && <span className="text-[10px] font-bold text-amber-600 bg-amber-100 px-1.5 rounded">MODIFIED</span>}
                                        </div>
                                        {changes.description ? (
                                            <div className="space-y-2 text-sm">
                                                <div className="text-gray-900">{event.description || <span className="italic text-gray-400">No description</span>}</div>
                                                <div className="pt-2 border-t border-amber-100 text-red-400 text-xs">
                                                    <span className="font-semibold uppercase text-red-300 mr-1">Previous:</span>
                                                    <span className="line-through opacity-70">{original?.description || 'No description'}</span>
                                                </div>
                                            </div>
                                        ) : (
                                            <p className="text-sm text-gray-600">{event.description || <span className="italic text-gray-400">No description</span>}</p>
                                        )}
                                    </div>

                                    {/* Time Diff */}
                                    <div className={`p-3 rounded-lg ${changes.time ? 'bg-amber-50/50 border border-amber-100' : 'bg-gray-50'}`}>
                                        <div className="flex items-center gap-2 mb-1.5">
                                            <Clock size={14} className="text-gray-400" />
                                            <span className="text-xs font-semibold text-gray-500 uppercase">Date & Time</span>
                                            {changes.time && <span className="text-[10px] font-bold text-amber-600 bg-amber-100 px-1.5 rounded">MODIFIED</span>}
                                        </div>
                                        {changes.time ? (
                                            <div className="space-y-2 text-sm">
                                                <div className="text-gray-900 font-medium">
                                                    {renderTime(event)}
                                                </div>
                                                <div className="pt-2 border-t border-amber-100 text-red-400 text-xs flex items-center gap-2">
                                                    <span className="font-semibold uppercase text-red-300 shrink-0">Was:</span>
                                                    <span className="line-through opacity-70 flex flex-wrap gap-1">
                                                        {original && renderTime(original)}
                                                    </span>
                                                </div>
                                            </div>
                                        ) : (
                                            <div className="text-sm text-gray-600">
                                                {renderTime(event)}
                                            </div>
                                        )}
                                    </div>

                                    {/* Location Diff */}
                                    <div className={`p-3 rounded-lg ${changes.location ? 'bg-amber-50/50 border border-amber-100' : 'bg-gray-50'}`}>
                                        <div className="flex items-center gap-2 mb-1.5">
                                            <MapPin size={14} className="text-gray-400" />
                                            <span className="text-xs font-semibold text-gray-500 uppercase">Location</span>
                                            {changes.location && <span className="text-[10px] font-bold text-amber-600 bg-amber-100 px-1.5 rounded">MODIFIED</span>}
                                        </div>
                                        {changes.location ? (
                                            <div className="space-y-1 text-sm">
                                                <div className="text-gray-900">{event.location || <span className="italic text-gray-400">No location</span>}</div>
                                                <div className="text-red-400 text-xs line-through opacity-70">
                                                    {original?.location || 'No location'}
                                                </div>
                                            </div>
                                        ) : (
                                            <p className="text-sm text-gray-600">{event.location || <span className="italic text-gray-400">No location</span>}</p>
                                        )}
                                    </div>
                                </div>
                            </div>

                            {/* Actions Footer */}
                            <div className="bg-gray-50 px-5 py-3 border-t border-gray-100 flex justify-end gap-3">
                                <button 
                                    onClick={() => handleEditApproval(event, false)}
                                    className="flex items-center gap-2 px-4 py-2 rounded-lg border border-gray-200 text-gray-600 bg-white hover:bg-gray-50 hover:text-red-600 hover:border-red-200 font-medium text-sm transition-colors"
                                >
                                    <RotateCcw size={16} />
                                    Reject Changes
                                </button>
                                <button 
                                    onClick={() => handleEditApproval(event, true)}
                                    className="flex items-center gap-2 px-4 py-2 rounded-lg bg-amber-500 text-white hover:bg-amber-600 shadow-sm hover:shadow font-medium text-sm transition-all"
                                >
                                    <Check size={16} />
                                    Approve Changes
                                </button>
                            </div>
                        </div>
                    );
                })}
            </div>
          </section>
      )}

      {/* Pending Events Section */}
      <section className="space-y-6">
        <div className="flex items-center justify-between">
            <h2 className="text-2xl font-bold text-gray-800">New Requests</h2>
            <div className="text-sm text-gray-500 font-medium bg-gray-100 px-3 py-1 rounded-full">
            {pendingEvents.length} Pending
            </div>
        </div>

        {pendingEvents.length === 0 ? (
            <div className="bg-white rounded-2xl p-12 text-center border border-dashed border-gray-300">
            <div className="mx-auto w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mb-4 text-gray-400">
                <Check size={32} />
            </div>
            <h3 className="text-lg font-medium text-gray-900">All caught up!</h3>
            <p className="text-gray-500 mt-1">There are no new events waiting for approval.</p>
            </div>
        ) : (
            <div className="grid gap-4">
            {pendingEvents.map((event) => (
                <div key={event.id} className="bg-white rounded-xl p-5 border border-gray-200 shadow-sm hover:shadow-md transition-all">
                <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                    <div className="space-y-3 flex-1">
                    <div className="flex items-start justify-between md:justify-start gap-3">
                        <span className={`px-2.5 py-0.5 rounded-md text-xs font-semibold ${getRegionClasses(event.region)}`}>
                            {event.region}
