export const checkAdminCredentials = async (username: string, password: string): Promise<boolean> => {
  try {
    const q = query(
      collection(db, "admins"), 
      where("username", "==", username), 
      where("password", "==", password)
    );
    const snapshot = await getDocs(q);
    return !snapshot.empty;
  } catch (e) {
    console.error("Error checking admin credentials:", e);
    return false;
  }
};

export const addEvent = async (event: Omit<CalendarEvent, 'id'>) => {
  try {
    const docRef = await addDoc(collection(db, "events"), event);
    return docRef.id;
  } catch (e) {
    console.error("Error adding document: ", e);
    throw e;
  }
};

export const getEvents = (onUpdate: (events: CalendarEvent[]) => void) => {
  const unsubscribe = onSnapshot(collection(db, "events"), (snapshot) => {
    const events: CalendarEvent[] = [];
    snapshot.forEach((doc) => {
      // We explicitly cast the data, ensuring the id is attached
      events.push({ id: doc.id, ...doc.data() } as CalendarEvent);
    });
    onUpdate(events);
  }, (error) => {
    console.error("Error getting documents: ", error);
  });
  return unsubscribe;
};

export const getPendingEvents = (onUpdate: (events: CalendarEvent[]) => void) => {
  const q = query(collection(db, "events"), where("status", "==", "pending"));
  const unsubscribe = onSnapshot(q, (snapshot) => {
    const events: CalendarEvent[] = [];
    snapshot.forEach((doc) => {
      events.push({ id: doc.id, ...doc.data() } as CalendarEvent);
    });
    onUpdate(events);
  }, (error) => {
    console.error("Error getting pending documents: ", error);
  });
  return unsubscribe;
};

export const getEditedEvents = (onUpdate: (events: CalendarEvent[]) => void) => {
  const q = query(collection(db, "events"), where("status", "==", "edited"));
  const unsubscribe = onSnapshot(q, (snapshot) => {
    const events: CalendarEvent[] = [];
    snapshot.forEach((doc) => {
      events.push({ id: doc.id, ...doc.data() } as CalendarEvent);
    });
    onUpdate(events);
  }, (error) => {
    console.error("Error getting edited documents: ", error);
  });
  return unsubscribe;
};

export const getRejectedEvents = (onUpdate: (events: CalendarEvent[]) => void) => {
  const q = query(collection(db, "events"), where("status", "==", "rejected"));
  const unsubscribe = onSnapshot(q, (snapshot) => {
    const events: CalendarEvent[] = [];
    snapshot.forEach((doc) => {
      events.push({ id: doc.id, ...doc.data() } as CalendarEvent);
    });
    onUpdate(events);
  }, (error) => {
    console.error("Error getting rejected documents: ", error);
  });
  return unsubscribe;
};

export const updateEvent = async (event: CalendarEvent) => {
  try {
    const { id, ...eventData } = event;
    const eventRef = doc(db, "events", id);
    await updateDoc(eventRef, eventData as any);
  } catch (e) {
    console.error("Error updating document: ", e);
    throw e;
  }
};

// Replaces the event with the new data and removes the originalData snapshot
export const approveEditedEvent = async (event: CalendarEvent) => {
    try {
        const { id, originalData, ...newData } = event;
        const eventRef = doc(db, "events", id);

        // Update with new data, set status to approved, and delete originalData field
        await updateDoc(eventRef, {
            ...newData,
            status: 'approved',
            originalData: deleteField()
        });
    } catch (e) {
        console.error("Error approving edit: ", e);
        throw e;
    }
};

// Reverts the event to originalData and sets status back to approved
export const rejectEditedEvent = async (event: CalendarEvent) => {
    try {
        if (!event.originalData) {
            throw new Error("Cannot reject edit: No original data found");
        }

        const { id } = event;
        const original = event.originalData;
        const eventRef = doc(db, "events", id);

        // Restore original data, ensure status is approved, and delete the snapshot
        await updateDoc(eventRef, {
            ...original,
            status: 'approved',
            originalData: deleteField()
        });
    } catch (e) {
        console.error("Error rejecting edit: ", e);
        throw e;
    }
};

export const deleteEvent = async (id: string) => {
  try {
    await deleteDoc(doc(db, "events", id));
  } catch (e) {
    console.error("Error deleting document: ", e);
    throw e;
  }
};

import React, { useState } from 'react';
import { Modal } from './Modal';
