                                                    </div>
                                                ) : (
                                                    <p className="text-sm text-gray-600">{event.location || <span className="italic text-gray-400">No location</span>}</p>
                                                )}
                                            </div>
                                        </div>
                                    </div>

                                    {/* Actions Footer */}
                                    <div className="bg-gray-50 px-5 py-3 border-t border-gray-100 flex justify-end gap-3">
                                        <button 
                                            onClick={() => handleEditApproval(event, false)}
                                            className="flex items-center gap-2 px-4 py-2 rounded-lg border border-gray-200 text-gray-600 bg-white hover:bg-gray-50 hover:text-red-600 hover:border-red-200 font-medium text-sm transition-colors"
                                        >
                                            <RotateCcw size={16} />
                                            Reject Changes
                                        </button>
                                        <button 
                                            onClick={() => handleEditApproval(event, true)}
                                            className="flex items-center gap-2 px-4 py-2 rounded-lg bg-amber-500 text-white hover:bg-amber-600 shadow-sm hover:shadow font-medium text-sm transition-all"
                                        >
                                            <Check size={16} />
                                            Approve Changes
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </section>
        )}

        {/* Rejected Events Tab */}
        {activeTab === 'rejected' && (
            <section className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300">
                {rejectedEvents.length === 0 ? (
                    <div className="bg-white rounded-2xl p-12 text-center border border-dashed border-gray-300">
                        <div className="mx-auto w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mb-4 text-gray-400">
                            <History size={32} />
                        </div>
                        <h3 className="text-lg font-medium text-gray-900">No rejected events</h3>
                        <p className="text-gray-500 mt-1">Rejected events history will appear here.</p>
                    </div>
                ) : (
                    <div className="grid gap-3">
                        {rejectedEvents.map((event) => (
                            <div key={event.id} className="bg-gray-50 rounded-lg p-4 border border-gray-200 opacity-80 hover:opacity-100 transition-all">
                                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                                    <div className="space-y-1">
                                        <h3 className="font-semibold text-gray-700">{event.title}</h3>
                                        <p className="text-xs text-gray-500">
                                            {formatFriendlyDate(event.start)} • {event.location || 'No location'}
                                        </p>
                                    </div>
                                    <button
                                        onClick={() => handleStatusChange(event, 'pending')}
                                        className="flex items-center gap-2 px-3 py-1.5 text-sm font-medium text-blue-600 bg-white border border-gray-200 hover:border-blue-300 hover:bg-blue-50 rounded-md transition-all shadow-sm"
                                    >
                                        <RotateCcw size={14} />
                                        Restore
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </section>
        )}
      </div>
    </div>
  );
};

