// Route new events based on status
export const addEvent = async (event: Omit<CalendarEvent, 'id'>) => {
  try {
    if (event.status === 'pending') {
        // Push to pending_events collection
        // This collection strictly contains 'pending' (new) and 'edited' (updates) events
        const docRef = await addDoc(collection(db, "pending_events"), {
            ...event,
            createdAt: serverTimestamp()
        });
        return docRef.id;
    } else {
        // Direct add to approved events (admin action)
        const docRef = await addDoc(collection(db, "events"), event);
        return docRef.id;
    }
  } catch (e) {
    console.error("Error adding document: ", e);
    throw e;
  }
};

// Get approved events from 'events' collection
export const getEvents = (onUpdate: (events: CalendarEvent[]) => void) => {
  // Only fetch events that are officially in the 'events' collection
  const q = query(collection(db, "events"));
  const unsubscribe = onSnapshot(q, (snapshot) => {
    const events: CalendarEvent[] = [];
    snapshot.forEach((doc) => {
      events.push({ id: doc.id, ...doc.data() } as CalendarEvent);
    });
    onUpdate(events);
  }, (error) => {
    console.error("Error getting documents: ", error);
  });
  return unsubscribe;
};

// Get pending NEW events from 'pending_events'
export const getPendingEvents = (onUpdate: (events: CalendarEvent[]) => void) => {
  const q = query(collection(db, "pending_events"), where("status", "==", "pending"));
  const unsubscribe = onSnapshot(q, (snapshot) => {
    const events: CalendarEvent[] = [];
    snapshot.forEach((doc) => {
      events.push({ id: doc.id, ...doc.data() } as CalendarEvent);
    });
    onUpdate(events);
  }, (error) => {
    console.error("Error getting pending documents: ", error);
  });
  return unsubscribe;
};

// Get edited events from 'pending_events'
export const getEditedEvents = (onUpdate: (events: CalendarEvent[]) => void) => {
  const q = query(collection(db, "pending_events"), where("status", "==", "edited"));
  const unsubscribe = onSnapshot(q, (snapshot) => {
    const events: CalendarEvent[] = [];
    snapshot.forEach((doc) => {
      events.push({ id: doc.id, ...doc.data() } as CalendarEvent);
    });
    onUpdate(events);
  }, (error) => {
    console.error("Error getting edited documents: ", error);
  });
  return unsubscribe;
};

// Get rejected events from 'rejected_events'
export const getRejectedEvents = (onUpdate: (events: CalendarEvent[]) => void) => {
  const q = query(collection(db, "rejected_events"));
  const unsubscribe = onSnapshot(q, (snapshot) => {
    const events: CalendarEvent[] = [];
    snapshot.forEach((doc) => {
      events.push({ id: doc.id, ...doc.data() } as CalendarEvent);
    });
    onUpdate(events);
  }, (error) => {
    console.error("Error getting rejected documents: ", error);
  });
  return unsubscribe;
};

// Handle updates / edit proposals
export const updateEvent = async (event: CalendarEvent) => {
  try {
    if (event.status === 'edited') {
        // User Edit Flow:
        // 1. Move/Copy data to 'pending_events'
        // 2. originalId links back to the live event in 'events'
        // 3. originalData contains the snapshot of the event before editing
        const { id, ...data } = event;

        await addDoc(collection(db, "pending_events"), {
            ...data,
            originalId: id, // Vital for applying the edit later
            createdAt: serverTimestamp()
        });

        // Note: The original event in 'events' collection remains untouched 
        // until an admin approves the edit.
    } else {
        // Admin Flow: Direct update to 'events' collection
        const { id, ...eventData } = event;
        const eventRef = doc(db, "events", id);
        await updateDoc(eventRef, eventData as any);
    }
  } catch (e) {
    console.error("Error updating document: ", e);
    throw e;
  }
};

// Admin: Approve a NEW pending event
export const approvePendingEvent = async (event: CalendarEvent) => {
    try {
        const { id, ...data } = event; // id is pending_events doc id

        // Move to 'events' collection
        await addDoc(collection(db, "events"), {
            ...data,
            status: 'approved'
        });

        // Clean up from 'pending_events'
        await deleteDoc(doc(db, "pending_events", id));
    } catch (e) {
        console.error("Error approving pending event:", e);
        throw e;
    }
};

// Admin: Approve an EDIT
export const approveEditedEvent = async (event: CalendarEvent) => {
    try {
        // event is the doc from 'pending_events'
        const { id, originalId, originalData, ...newData } = event as any;

        if (!originalId) throw new Error("Missing originalId for edited event");

        // Apply changes to the live event in 'events'
        const eventRef = doc(db, "events", originalId);
        await updateDoc(eventRef, {
            ...newData,
            status: 'approved'
        });

        // Clean up the request from 'pending_events'
        await deleteDoc(doc(db, "pending_events", id));
    } catch (e) {
        console.error("Error approving edit: ", e);
        throw e;
    }
};

// Admin: Reject a request (new or edit)
export const rejectRequest = async (event: CalendarEvent) => {
    try {
        const { id, ...data } = event;

        // Move to 'rejected_events' for history
        await addDoc(collection(db, "rejected_events"), {
            ...data,
            status: 'rejected',
            rejectedAt: serverTimestamp()
        });

        // Clean up from 'pending_events'
        await deleteDoc(doc(db, "pending_events", id));
    } catch (e) {
        console.error("Error rejecting request: ", e);
        throw e;
    }
};

// Admin: Restore a rejected event (move back to pending)
export const restoreRejectedEvent = async (event: CalendarEvent) => {
    try {
        const { id, ...data } = event;

        // Move back to 'pending_events'
        await addDoc(collection(db, "pending_events"), {
            ...data,
            status: 'pending' // Default back to pending for review
        });

        // Remove from 'rejected_events'
        await deleteDoc(doc(db, "rejected_events", id));
    } catch (e) {
        console.error("Error restoring event: ", e);
        throw e;
    }
};

// Delete event from 'events' collection
export const deleteEvent = async (id: string) => {
  try {
    await deleteDoc(doc(db, "events", id));
  } catch (e) {
    console.error("Error deleting document: ", e);
    throw e;
  }
};

