// ... imports
import {
  addDoc,
  collection,
  deleteDoc,
  doc,
  getDocs,
  query,
  updateDoc,
  where,
} from "firebase/firestore";
import { db } from "./firebaseConfig";

export interface CalendarEvent {
  id: string;
  title: string;
  start: Date;
  end: Date;
  description?: string;
  location?: string;
  status: "active" | "deleted";
}

export const addEvent = async (newEvent: Omit<CalendarEvent, "id">) => {
  try {
    const docRef = await addDoc(collection(db, "events"), {
      ...newEvent,
      status: "active",
    });
    return docRef.id;
  } catch (e) {
    console.error("Error adding document: ", e);
    return null;
  }
};

export const getEvents = (onUpdate: (events: CalendarEvent[]) => void) => {
  const q = query(collection(db, "events"), where("status", "!=", "deleted"));
  const unsubscribe = onSnapshot(q, (querySnapshot) => {
    const events: CalendarEvent[] = [];
    querySnapshot.forEach((doc) => {
      const eventData = doc.data() as Omit<CalendarEvent, "id">;
      events.push({ id: doc.id, ...eventData } as CalendarEvent);
    });
    onUpdate(events);
  });
  return unsubscribe;
};

export const deleteEvent = async (id: string) => {
  if (!id) {
    console.error("No ID provided for deletion");
    return;
  }
  try {
    const eventDocRef = doc(db, "events", id);
    const eventDoc = await getDoc(eventDocRef);
    if (!eventDoc.exists()) {
      console.error(`Event with ID ${id} not found`);
      return;
    }

    const eventData = eventDoc.data() as CalendarEvent;

    // Move to deleted_events
    const deletedEventsCollection = collection(db, "deleted_events");
    const docRef = await addDoc(deletedEventsCollection, {
      ...eventData,
      status: "deleted",
      originalId: id,
    });

    // Delete the original event
    await deleteDoc(eventDocRef);
  } catch (e) {
    console.error("Error deleting event: ", e);
  }
};

]]></content>
</change>
</changes>
```


**Finalizing Code Verification**

I'm now verifying the final implementation and changes. The updated `getEvents` function with the filter ensures only active events are retrieved. The `deleteEvent` function moves the event to `deleted_events` and deletes the original document. All updates are made. I am confident that the code now meets all requirements.


**Refining Event Routing**

I'm now refining event routing. I've considered that the status can vary and have altered the code for routing based on 'pending' status. Pending events are added to the `pending_events` collection. Events with any other status get added directly to `events`.


**Optimizing Event Retrieval**

I'm now separating event fetching by status. Newly added events with "pending" status are retrieved from `pending_events`, while others, excluding "deleted," go into `events`.  I've added a separate `getPendingEvents` and `getEditedEvents` for enhanced organization.


**Structuring Event Data Retrieval**

I'm now restructuring data retrieval, and ensuring there are specific functions for each event status. I'm adding `getEditedEvents` and `getRejectedEvents` to handle edited and rejected events respectively. I'll make sure each function has an appropriate error handler.


**Refining Event Update Logic**

I am now refining how events are updated, particularly in cases of user edits versus admin actions. Edited events now move to `pending_events` with an `originalId` link, and the original event remains untouched. The existing event receives updates directly from the admin. The goal is now to fully implement this system.


**Refining Approval Process**

I'm now refining the event approval process. Approved events are being moved from `pending_events` to the `events` collection. I am implementing error handling and a cleanup step to delete the event from `pending_events` after approval to maintain data integrity and prevent duplicated events. I'm focusing on clarifying event status transitions.


**Implementing Admin Functionality**

I'm now implementing functions for admin actions: approving, rejecting, and restoring events, while handling document updates, moving between collections. I am currently working on approving and rejecting events, including data transfer, deletion from `pending_events`, and adding rejection timestamps. I am also working on `restoreRejectedEvent` functionality.


**Refining Restoration Functionality**

I'm now refining the event restoration, specifically `restoreRejectedEvent`, and the `deleteEvent` functionality. Restoration now moves events from `rejected_events` back to `pending_events` with the status set to 'pending'. I'm verifying data transfer to the `deleted_events` collection. I am reviewing error handling and edge cases.

