// Delete event: Move to deleted_events, update status to 'deleted', then remove from events
export const deleteEvent = async (id: string) => {
  console.log("Attempting to delete event with ID:", id);
  try {
    if (!id) throw new Error("Invalid ID provided for deletion");

    const eventRef = doc(db, "events", id);
    const eventSnap = await getDoc(eventRef);

    if (eventSnap.exists()) {
        const eventData = eventSnap.data();

        // 1. Update status to 'deleted' in the original document
        await updateDoc(eventRef, { status: 'deleted' });

        // 2. Add to deleted_events with status 'deleted'
        await addDoc(collection(db, "deleted_events"), {
            ...eventData,
            status: 'deleted',
            deletedAt: serverTimestamp(),
            originalId: id
        });

        // 3. Remove from the main events collection
        await deleteDoc(eventRef);
        console.log("Event moved to deleted_events and removed from events successfully");
    } else {
        console.warn("Event not found in events collection, cannot delete.");
    }
  } catch (e) {
    console.error("Error deleting document: ", e);
    throw e;
  }
};

export type RecurrenceType = 'none' | 'monthly' | 'yearly';

export interface CalendarEvent {
  id: string;
  title: string;
  description?: string;
  start: string; // ISO 8601 date string
  end: string;   // ISO 8601 date string
  region: Region;
  isAllDay: boolean;
  location?: string;
  recurrence?: RecurrenceType;
  status?: 'pending' | 'approved' | 'rejected' | 'edited' | 'deleted';
  originalData?: CalendarEvent; // Stores the state of the event before editing
}

export enum Region {
  IWAMI = 'Iwami (West)',
  IZUMO = 'Izumo (East)',
  OKI = 'Oki'
}

export interface DayData {
  date: Date;
  isCurrentMonth: boolean;
  isToday: boolean;
  events: CalendarEvent[];
}

