// Delete event: Soft delete by updating status to 'deleted', then archive copy
export const deleteEvent = async (id: string) => {
  console.log("Attempting to delete event with ID:", id);
  try {
    if (!id) throw new Error("Invalid ID provided for deletion");

    const eventRef = doc(db, "events", id);
    const eventSnap = await getDoc(eventRef);

    if (eventSnap.exists()) {
        const eventData = eventSnap.data();

        // 1. Update status to 'deleted' in the original document
        // This satisfies the requirement to "change the status of the event to deleted"
        await updateDoc(eventRef, { status: 'deleted' });

        // 2. Add to deleted_events with status 'deleted'
        // This satisfies the requirement to "move the event document information to the deleted_events collection"
        await addDoc(collection(db, "deleted_events"), {
            ...eventData,
            status: 'deleted',
            deletedAt: serverTimestamp(),
            originalId: id
        });

        // Note: We do NOT delete the original document physically.
        // This ensures the status change remains visible in the 'events' collection (soft delete).
        // The getEvents function filters these out.

        console.log("Event status changed to 'deleted' and archived to deleted_events");
    } else {
        console.warn("Event not found in events collection, cannot delete.");
    }
  } catch (e) {
    console.error("Error deleting document: ", e);
    throw e;
  }
};

